-- Minimal base64 decoder for the embedded pack.
local B64 = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local b64lookup
local function base64Decode(data)
    if not b64lookup then
        b64lookup = {}
        for i = 1, #B64 do
            b64lookup[string.byte(B64, i)] = i - 1
        end
    end
    data = string.gsub(data, "[^" .. B64 .. "=]", "")
    local out = {}
    local i = 1
    local n = #data
    while i <= n do
        local c1 = b64lookup[string.byte(data, i)] or 0
        local c2 = b64lookup[string.byte(data, i + 1)] or 0
        local c3 = b64lookup[string.byte(data, i + 2)]
        local c4 = b64lookup[string.byte(data, i + 3)]
        local b1 = c1 * 4 + math.floor(c2 / 16)
        out[#out + 1] = string.char(b1)
        if c3 ~= nil and string.byte(data, i + 2) ~= 61 then
            local b2 = (c2 % 16) * 16 + math.floor(c3 / 4)
            out[#out + 1] = string.char(b2)
            if c4 ~= nil and string.byte(data, i + 3) ~= 61 then
                local b3 = (c3 % 4) * 64 + c4
                out[#out + 1] = string.char(b3)
            end
        end
        i = i + 4
    end
    return table.concat(out)
end

-- Decode the embedded pack to a cache folder once, then load via getcustomasset.
local CACHE_DIR = "NewReality/iconcache/"
local cacheReady = false
local function ensureCache()
    if cacheReady then return cacheReady end
    pcall(function()
        if makefolder and isfolder and not isfolder("NewReality") then makefolder("NewReality") end
        if makefolder and isfolder and not isfolder(CACHE_DIR) then makefolder(CACHE_DIR) end
        cacheReady = true
    end)
    return cacheReady
end

local function embeddedAsset(name)
    local b64 = ICON_DATA[name]
    if not b64 then return nil end
    if not (writefile and getcustomasset) then return nil end
    local path = CACHE_DIR .. name .. ".png"
    local ok, asset = pcall(function()
        ensureCache()
        -- Always rewrite so updated embedded data is never masked by a stale file.
        writefile(path, base64Decode(b64))
        return getcustomasset(path)
    end)
    if ok then return asset end
    return nil
end

local function probeIconFolder()
    if iconFolder ~= nil then
        return iconFolder
    end
    iconFolder = false
    pcall(function()
        if not isfile then return end
        for _, dir in ipairs(ICON_DIRS) do
            if isfile(dir .. "settings.png") then
                iconFolder = dir
                return
            end
        end
    end)
    return iconFolder
end

local function iconAsset(name)
    if not name or name == "" then
        return nil
    end
    -- Explicit overrides and direct asset ids pass straight through.
    if Interface.icons[name] then
        name = Interface.icons[name]
    end
    if string.sub(name, 1, 3) == "rbx" or string.sub(name, 1, 4) == "http" then
        return name
    end
    name = string.lower(name)
    if iconCache[name] ~= nil then
        return iconCache[name] or nil
    end
    local result = false
    -- Embedded pack first (self contained), then an optional workspace folder.
    local emb = embeddedAsset(name)
    if emb then
        result = emb
    else
        pcall(function()
            if not (isfile and getcustomasset) then return end
            local dir = probeIconFolder()
            if dir then
                local path = dir .. name .. ".png"
                if isfile(path) then
                    result = getcustomasset(path)
                end
            end
        end)
    end
    if not iconLogged then
        iconLogged = true
        local count = 0
        for _ in pairs(ICON_DATA) do count += 1 end
        if count > 0 then
            print("[NewReality] embedded icons: " .. count)
        else
            warn("[NewReality] no embedded icons present")
        end
    end
    iconCache[name] = result
    return result or nil
end
Interface.iconAsset = iconAsset

-- Force a specific icon folder (relative to the executor workspace).
function Interface.setIconFolder(folder)
    iconFolder = folder
    iconCache = {}
    iconLogged = false
end

local function makeIcon(parent, name, size, color)
    local img = Instance.new("ImageLabel")
    img.BackgroundTransparency = 1
    img.Size = size or UDim2.new(0, 18, 0, 18)
    img.Image = iconAsset(name) or ""
    img.ImageColor3 = color or PALETTE.text
    img.ScaleType = Enum.ScaleType.Fit
    img.Parent = parent
    return img
end

local function guiParent()
    if gethui then
        return gethui()
    end
    local ok, coreGui = pcall(game.GetService, game, "CoreGui")
    if ok and coreGui then
        return coreGui
    end
    return LocalPlayer:WaitForChild("PlayerGui")
end

local function nextOrder(holder)
    local n = (holder:GetAttribute("nrOrder") or 0) + 1
    holder:SetAttribute("nrOrder", n)
    return n
end

local function tween(instance, time, props, style, dir)
    local info = TweenInfo.new(time, style or Enum.EasingStyle.Quad, dir or Enum.EasingDirection.Out)
    local t = TweenService:Create(instance, info, props)
    t:Play()
    return t
end

-- Gentle icon colour transition.
local function tintIcon(img, color)
    tween(img, 0.22, { ImageColor3 = color })
end

local function makeDraggable(window, handle)
    handle.Active = true
    local dragging, dragStart, startPos
    handle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
            or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            dragStart = input.Position
            startPos = window.Position
            input.Changed:Connect(function()
                if input.UserInputState == Enum.UserInputState.End then
                    dragging = false
                end
            end)
        end
    end)
    UserInputService.InputChanged:Connect(function(input)
        if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement
            or input.UserInputType == Enum.UserInputType.Touch) then
            local delta = input.Position - dragStart
            window.Position = UDim2.new(
                startPos.X.Scale, startPos.X.Offset + delta.X,
                startPos.Y.Scale, startPos.Y.Offset + delta.Y
            )
        end
    end)
end

-- The NewReality brand text with the white to accent scrolling gradient.
local function animateBrand(label)
    local gradient = Instance.new("UIGradient")
    local function rebuild()
        gradient.Color = ColorSequence.new({
            ColorSequenceKeypoint.new(0, PALETTE.text),
            ColorSequenceKeypoint.new(0.5, PALETTE.accent),
            ColorSequenceKeypoint.new(1, PALETTE.text),
        })
    end
    rebuild()
    gradient.Parent = label
    task.spawn(function()
        while label.Parent do
            local elapsed = 0
            while elapsed < 1 and label.Parent do
                elapsed += RunService.RenderStepped:Wait()
                gradient.Offset = Vector2.new(-1 + elapsed * 2, 0)
            end
        end
    end)
    return rebuild
end

-- Control builders. Each builds into a container (a card body or a popover body)
-- and returns the created row. ctx is the window, used for the overlay layer.

local function controlRow(parent, height)
    local row = Instance.new("Frame")
    row.Size = UDim2.new(1, 0, 0, height)
    row.BackgroundTransparency = 1
    row.LayoutOrder = nextOrder(parent)
    row.Parent = parent
    return row
end

local function rowLabel(row, text, rightInset)
    local label = Instance.new("TextLabel")
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(1, -(rightInset or 54), 1, 0)
    label.FontFace = FONT
    label.TextSize = 15
    label.TextColor3 = PALETTE.text
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.TextTruncate = Enum.TextTruncate.AtEnd
    label.Text = text
    label.Parent = row
    return label
end

local function makePill(row, ctx, get, set)
    local pill = Instance.new("TextButton")
    pill.AnchorPoint = Vector2.new(1, 0.5)
    pill.Position = UDim2.new(1, 0, 0.5, 0)
    pill.Size = UDim2.new(0, 44, 0, 22)
    pill.AutoButtonColor = false
    pill.Text = ""
    pill.BackgroundColor3 = PALETTE.track
    pill.BorderSizePixel = 0
    pill.Parent = row
    corner(pill, 11)

    local knob = Instance.new("Frame")
    knob.Size = UDim2.new(0, 16, 0, 16)
    knob.Position = UDim2.new(0, 3, 0.5, -8)
    knob.BackgroundColor3 = PALETTE.text
    knob.BorderSizePixel = 0
    knob.Parent = pill
    corner(knob, 8)

    local function render(value)
        tween(pill, 0.16, { BackgroundColor3 = value and PALETTE.accent or PALETTE.track })
        tween(knob, 0.16, { Position = value and UDim2.new(1, -19, 0.5, -8) or UDim2.new(0, 3, 0.5, -8) }, Enum.EasingStyle.Back)
    end
    render(get())
    -- Re-apply on theme change or config load (move the knob too, not just colour).
    if ctx and ctx._refresh then
        table.insert(ctx._refresh, function()
            render(get())
        end)
    end
    pill.MouseButton1Click:Connect(function()
        local value = not get()
        set(value)
        render(value)
    end)
    return pill
end

local function gearIcon(row)
    local btn = Instance.new("TextButton")
    btn.AnchorPoint = Vector2.new(1, 0.5)
    btn.Position = UDim2.new(1, -54, 0.5, 0)
    btn.Size = UDim2.new(0, 24, 0, 24)
    btn.BackgroundTransparency = 1
    btn.Text = ""
    btn.Parent = row
    local img = makeIcon(btn, "settings", UDim2.new(1, 0, 1, 0), PALETTE.text)
    img.Active = false
    -- Fallback drawn cog if the settings icon file is missing.
    if img.Image == "" then
        for i = 0, 2 do
            local tooth = Instance.new("Frame")
            tooth.AnchorPoint = Vector2.new(0.5, 0.5)
            tooth.Position = UDim2.new(0.5, 0, 0.5, 0)
            tooth.Size = UDim2.new(0, 16, 0, 5)
            tooth.Rotation = i * 60
            tooth.BackgroundColor3 = PALETTE.text
            tooth.BorderSizePixel = 0
            corner(tooth, 2)
            tooth.Parent = btn
        end
        local hole = Instance.new("Frame")
        hole.AnchorPoint = Vector2.new(0.5, 0.5)
        hole.Position = UDim2.new(0.5, 0, 0.5, 0)
        hole.Size = UDim2.new(0, 7, 0, 7)
        hole.BackgroundColor3 = PALETTE.card
        hole.BorderSizePixel = 0
        corner(hole, 4)
        hole.Parent = btn
    end
    btn.MouseEnter:Connect(function() if img.Image ~= "" then tintIcon(img, PALETTE.accent) end end)
    btn.MouseLeave:Connect(function() if img.Image ~= "" then tintIcon(img, PALETTE.text) end end)
    return btn
end

local Controls = {}

-- Forward declaration so popovers can host the same controls via a Card.
local Card

function Controls.label(parent, text)
    local row = controlRow(parent, 18)
    local label = Instance.new("TextLabel")
    label.BackgroundTransparency = 1
    label.Size = UDim2.new(1, 0, 1, 0)
    label.FontFace = FONT
    label.TextSize = 13
    label.TextColor3 = PALETTE.subtext
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Text = text
    label.Parent = row
    return row
end

function Controls.toggle(parent, ctx, text, get, set, buildSettings)
    local row = controlRow(parent, 30)
    rowLabel(row, text, buildSettings and 84 or 54)
    makePill(row, ctx, get, set)

    if buildSettings then
        local gear = gearIcon(row)
        local popover
        gear.MouseButton1Click:Connect(function()
            if popover and popover.Parent then
                popover:Destroy()
                popover = nil
                return
            end
            if ctx.closeOverlays then ctx.closeOverlays() end
            if ctx.showBackdrop then ctx.showBackdrop() end
            popover = Instance.new("CanvasGroup")
            popover.Name = "Popover"
            popover.Size = UDim2.new(0, 270, 0, 0)
            popover.AutomaticSize = Enum.AutomaticSize.Y
            popover.BackgroundColor3 = PALETTE.card
            popover.BorderSizePixel = 0
            popover.ZIndex = 50
            popover.Visible = true
            popover.Parent = ctx.overlay
            corner(popover, 8)
            stroke(popover, PALETTE.stroke, 1, 0.2)
            local body = Instance.new("Frame")
            body.BackgroundTransparency = 1
            body.Size = UDim2.new(1, 0, 0, 0)
            body.AutomaticSize = Enum.AutomaticSize.Y
            body.Parent = popover
            listLayout(body, 8)
            padding(body, 12)
            local title = Instance.new("TextLabel")
            title.BackgroundTransparency = 1
            title.Size = UDim2.new(1, 0, 0, 18)
            title.FontFace = FONT
            title.TextSize = 15
            title.TextColor3 = PALETTE.text
            title.TextXAlignment = Enum.TextXAlignment.Left
            title.Text = text .. " Settings"
            title.LayoutOrder = nextOrder(body)
            title.Parent = body
            buildSettings(Card.new(body, ctx))
            local px = gear.AbsolutePosition.X - ctx.window.AbsolutePosition.X - 230
            local py = gear.AbsolutePosition.Y - ctx.window.AbsolutePosition.Y + 26
            popover.Position = ctx.fitPanel and ctx.fitPanel(px, py, 270, 220) or UDim2.new(0, px, 0, py)
            popover.GroupTransparency = 1
            tween(popover, 0.18, { GroupTransparency = 0 })
        end)
    end
    return row
end

function Controls.button(parent, ctx, text, onClick)
    local row = controlRow(parent, 34)
    local button = Instance.new("TextButton")
    button.Size = UDim2.new(1, 0, 1, 0)
    themed(button, "BackgroundColor3", "control")
    button.BorderSizePixel = 0
    button.AutoButtonColor = false
    button.FontFace = FONT
    button.TextSize = 14
    button.TextColor3 = PALETTE.text
    button.Text = text
    button.Parent = row
    corner(button, 6)
    button.MouseEnter:Connect(function()
        tween(button, 0.12, { BackgroundColor3 = PALETTE.controlHover })
    end)
    button.MouseLeave:Connect(function()
        tween(button, 0.12, { BackgroundColor3 = PALETTE.control })
    end)
    local scale = Instance.new("UIScale")
    scale.Parent = button
    button.MouseButton1Down:Connect(function() tween(scale, 0.08, { Scale = 0.97 }) end)
    button.MouseButton1Up:Connect(function() tween(scale, 0.08, { Scale = 1 }) end)
    button.MouseButton1Click:Connect(function()
        if onClick then onClick() end
    end)
    return row
end

