function Controls.slider(parent, ctx, text, min, max, get, set, decimals, format)
    local row = controlRow(parent, 44)
    local label = Instance.new("TextLabel")
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 0, 0, 0)
    label.Size = UDim2.new(1, -54, 0, 20)
    label.FontFace = FONT
    label.TextSize = 15
    label.TextColor3 = PALETTE.text
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Text = text
    label.Parent = row

    local valueBox = Instance.new("TextBox")
    valueBox.AnchorPoint = Vector2.new(1, 0)
    valueBox.Position = UDim2.new(1, 0, 0, 0)
    valueBox.Size = UDim2.new(0, 50, 0, 20)
    themed(valueBox, "BackgroundColor3", "control")
    valueBox.BorderSizePixel = 0
    valueBox.FontFace = FONT
    valueBox.TextSize = 13
    valueBox.TextColor3 = PALETTE.text
    valueBox.Text = "0"
    valueBox.ClearTextOnFocus = false
    valueBox.TextXAlignment = Enum.TextXAlignment.Center
    valueBox.Parent = row
    corner(valueBox, 5)

    local track = Instance.new("TextButton")
    track.Position = UDim2.new(0, 0, 1, -10)
    track.Size = UDim2.new(1, 0, 0, 6)
    themed(track, "BackgroundColor3", "track")
    track.BorderSizePixel = 0
    track.AutoButtonColor = false
    track.Text = ""
    track.Parent = row
    corner(track, 3)

    local fill = Instance.new("Frame")
    themed(fill, "BackgroundColor3", "accent")
    fill.BorderSizePixel = 0
    fill.Parent = track
    corner(fill, 3)

    local knob = Instance.new("Frame")
    knob.AnchorPoint = Vector2.new(0.5, 0.5)
    knob.Size = UDim2.new(0, 12, 0, 12)
    knob.BackgroundColor3 = PALETTE.text
    knob.BorderSizePixel = 0
    knob.ZIndex = 2
    knob.Parent = track
    corner(knob, 6)

    local function clampValue(value)
        if decimals and decimals > 0 then
            local mult = 10 ^ decimals
            return math.floor(value * mult + 0.5) / mult
        end
        return math.floor(value + 0.5)
    end
    local function render(value)
        local ratio = (max > min) and math.clamp((value - min) / (max - min), 0, 1) or 0
        fill.Size = UDim2.new(ratio, 0, 1, 0)
        knob.Position = UDim2.new(ratio, 0, 0.5, 0)
        valueBox.Text = format and format(value) or tostring(value)
    end
    render(get())

    -- The value box accepts a typed number (clamped to range).
    valueBox.FocusLost:Connect(function()
        local typed = tonumber(string.match(valueBox.Text, "[%-%d%.]+"))
        if typed then
            local value = math.clamp(clampValue(typed), min, max)
            set(value)
            render(value)
        else
            render(get())
        end
    end)

    local dragging = false
    local function setFromX(x)
        local ratio = math.clamp((x - track.AbsolutePosition.X) / math.max(track.AbsoluteSize.X, 1), 0, 1)
        local value = clampValue(min + ratio * (max - min))
        set(value)
        render(value)
    end
    track.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            setFromX(input.Position.X)
        end
    end)
    UserInputService.InputChanged:Connect(function(input)
        if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
            setFromX(input.Position.X)
        end
    end)
    UserInputService.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
            dragging = false
        end
    end)
    if ctx and ctx._refresh then table.insert(ctx._refresh, function() render(get()) end) end
    return row
end

function Controls.keybind(parent, ctx, text, getKey, setKey, opts)
    opts = opts or {}
    local multi = opts.multi
    local row = controlRow(parent, 30)
    rowLabel(row, text, 150)
    local kbIcon = makeIcon(row, "keyboard", UDim2.new(0, 22, 0, 22), PALETTE.text)
    kbIcon.AnchorPoint = Vector2.new(1, 0.5)
    kbIcon.Position = UDim2.new(1, -126, 0.5, 0)
    local button = Instance.new("TextButton")
    button.AnchorPoint = Vector2.new(1, 0.5)
    button.Position = UDim2.new(1, 0, 0.5, 0)
    button.Size = UDim2.new(0, 116, 0, 24)
    themed(button, "BackgroundColor3", "control")
    button.BorderSizePixel = 0
    button.AutoButtonColor = false
    button.FontFace = FONT
    button.TextSize = 13
    button.TextColor3 = PALETTE.text
    button.TextTruncate = Enum.TextTruncate.AtEnd
    button.Parent = row
    corner(button, 6)

    -- Normalise the stored value into a list of key names.
    local function keyList()
        local v = getKey()
        if multi then
            if type(v) == "table" then return v end
            return {}
        else
            if v == nil or v == "" or v == "None" then return {} end
            return { tostring(v) }
        end
    end
    local function display()
        local list = keyList()
        if #list == 0 then return "None" end
        return table.concat(list, " + ")
    end
    local function commit(list)
        if multi then
            setKey(list)
        else
            setKey(list[1])
        end
        button.Text = display()
    end
    button.Text = display()

    local capturing = false
    button.MouseEnter:Connect(function()
        if not capturing then tween(button, 0.12, { BackgroundColor3 = PALETTE.controlHover }) end
    end)
    button.MouseLeave:Connect(function()
        if not capturing then tween(button, 0.12, { BackgroundColor3 = PALETTE.control }) end
    end)
    -- Left click: capture a key. Right click: clear the bind.
    button.MouseButton1Click:Connect(function()
        capturing = true
        button.Text = "..."
        button.TextColor3 = PALETTE.accent
    end)
    button.MouseButton2Click:Connect(function()
        commit({})
        button.TextColor3 = PALETTE.text
    end)
    UserInputService.InputBegan:Connect(function(input, gpe)
        if capturing and input.UserInputType == Enum.UserInputType.Keyboard then
            capturing = false
            button.TextColor3 = PALETTE.text
            local name = input.KeyCode.Name
            if name == "Escape" or name == "Backspace" or name == "Delete" then
                commit({})
                return
            end
            if multi then
                local list = keyList()
                local has = false
                for _, v in ipairs(list) do if v == name then has = true end end
                if not has then table.insert(list, name) end
                commit(list)
            else
                commit({ name })
            end
            return
        end
        -- Fire the callback when a bound key is pressed.
        if not capturing and not gpe and opts.callback and input.UserInputType == Enum.UserInputType.Keyboard then
            for _, v in ipairs(keyList()) do
                if v == input.KeyCode.Name then
                    opts.callback(input.KeyCode)
                    break
                end
            end
        end
    end)
    if ctx and ctx._refresh then table.insert(ctx._refresh, function() button.Text = display() end) end
    -- Register the bind so the keybind panel can list it.
    if ctx and ctx._binds and opts.list ~= false then
        table.insert(ctx._binds, {
            label = opts.listName or text,
            keys = keyList,
            active = opts.active,
        })
    end
    return row
end

function Controls.dropdown(parent, ctx, text, options, get, set, opts)
    opts = opts or {}
    local multi = opts.multi
    -- options may be a list or a function returning a list (for dynamic lists).
    local function getOptions()
        local list = (type(options) == "function") and options() or options
        return type(list) == "table" and list or {}
    end
    local row = controlRow(parent, 30)
    rowLabel(row, text, 150)

    local button = Instance.new("TextButton")
    button.AnchorPoint = Vector2.new(1, 0.5)
    button.Position = UDim2.new(1, 0, 0.5, 0)
    button.Size = UDim2.new(0, 140, 0, 26)
    themed(button, "BackgroundColor3", "control")
    button.BorderSizePixel = 0
    button.AutoButtonColor = false
    button.FontFace = FONT
    button.TextSize = 13
    button.TextColor3 = PALETTE.text
    button.TextXAlignment = Enum.TextXAlignment.Left
    button.TextTruncate = Enum.TextTruncate.AtEnd
    button.Parent = row
    corner(button, 6)
    padding(button, nil, { left = 10, right = 24 })

    local arrow = makeIcon(row, "chevron-down", UDim2.new(0, 18, 0, 18), PALETTE.text)
    arrow.AnchorPoint = Vector2.new(1, 0.5)
    arrow.Position = UDim2.new(1, -8, 0.5, 0)
    button.MouseEnter:Connect(function() tween(button, 0.12, { BackgroundColor3 = PALETTE.controlHover }) end)
    button.MouseLeave:Connect(function() tween(button, 0.12, { BackgroundColor3 = PALETTE.control }) end)

    local selected = {}
    if multi then
        if type(get()) == "table" then
            for _, v in ipairs(get()) do selected[v] = true end
        end
    end
    local function labelText()
        if multi then
            local list = {}
            for _, opt in ipairs(getOptions()) do
                if selected[opt] then table.insert(list, opt) end
            end
            return #list == 0 and "None" or table.concat(list, ", ")
        end
        return tostring(get())
    end
    button.Text = labelText()
    if ctx and ctx._refresh then
        table.insert(ctx._refresh, function()
            if multi then
                selected = {}
                if type(get()) == "table" then
                    for _, v in ipairs(get()) do selected[v] = true end
                end
            end
            button.Text = labelText()
        end)
    end

    local panel
    button.MouseButton1Click:Connect(function()
        if panel and panel.Parent then
            panel:Destroy()
            panel = nil
            return
        end
        if ctx.closeOverlays then ctx.closeOverlays() end
        if ctx.showBackdrop then ctx.showBackdrop() end
        panel = Instance.new("CanvasGroup")
        panel.BackgroundColor3 = PALETTE.card
        panel.BorderSizePixel = 0
        panel.ZIndex = 60
        panel.Size = UDim2.new(0, 210, 0, 0)
        panel.AutomaticSize = Enum.AutomaticSize.Y
        local dx = button.AbsolutePosition.X - ctx.window.AbsolutePosition.X - 70
        local dy = button.AbsolutePosition.Y - ctx.window.AbsolutePosition.Y + 32
        panel.Position = ctx.fitPanel and ctx.fitPanel(dx, dy, 210, 240) or UDim2.new(0, dx, 0, dy)
        panel.Parent = ctx.overlay
        corner(panel, 10)
        stroke(panel, PALETTE.stroke, 1, 0.2)
        -- Fade and slide in.
        panel.GroupTransparency = 1
        local destY = panel.Position
        panel.Position = destY - UDim2.new(0, 0, 0, 6)
        tween(panel, 0.16, { GroupTransparency = 0, Position = destY })
        listLayout(panel, 0)

        -- Search as a flush header at the top of the panel (top corners follow
        -- the panel rounding via the CanvasGroup clip, bottom edge is square).
        local searchBox
        if opts.search then
            local header = Instance.new("Frame")
            header.Size = UDim2.new(1, 0, 0, 38)
            header.BackgroundColor3 = PALETTE.control
            header.BorderSizePixel = 0
            header.LayoutOrder = 0
            header.Parent = panel
            local sicon = makeIcon(header, "search", UDim2.new(0, 16, 0, 16), PALETTE.subtext)
            sicon.AnchorPoint = Vector2.new(0, 0.5)
            sicon.Position = UDim2.new(0, 12, 0.5, 0)
            searchBox = Instance.new("TextBox")
            searchBox.BackgroundTransparency = 1
            searchBox.Position = UDim2.new(0, 36, 0, 0)
            searchBox.Size = UDim2.new(1, -46, 1, 0)
            searchBox.FontFace = FONT
            searchBox.TextSize = 13
            searchBox.TextColor3 = PALETTE.text
            searchBox.PlaceholderColor3 = PALETTE.subtext
            searchBox.PlaceholderText = "Search.."
            searchBox.Text = ""
            searchBox.ClearTextOnFocus = false
            searchBox.TextXAlignment = Enum.TextXAlignment.Left
            searchBox.Parent = header
        end

        local body = Instance.new("Frame")
        body.BackgroundTransparency = 1
        body.Size = UDim2.new(1, 0, 0, 0)
        body.AutomaticSize = Enum.AutomaticSize.Y
        body.LayoutOrder = 1
        body.Parent = panel
        listLayout(body, 3)
        padding(body, 6)

        local optRows = {}
        local function paint(refs, opt)
            local on = (multi and selected[opt] and true) or ((not multi) and tostring(get()) == tostring(opt))
            refs.on = on
            refs.btn.BackgroundColor3 = PALETTE.controlHover
            refs.btn.BackgroundTransparency = on and 0 or 1
            refs.label.TextColor3 = on and PALETTE.accent or PALETTE.text
        end
        for _, opt in ipairs(getOptions()) do
            local optBtn = Instance.new("TextButton")
            optBtn.Size = UDim2.new(1, 0, 0, 32)
            optBtn.BackgroundColor3 = PALETTE.controlHover
            optBtn.BackgroundTransparency = 1
            optBtn.BorderSizePixel = 0
            optBtn.AutoButtonColor = false
            optBtn.Text = ""
            optBtn.LayoutOrder = nextOrder(body)
            optBtn.Parent = body
            corner(optBtn, 8)

            local optLabel = Instance.new("TextLabel")
            optLabel.BackgroundTransparency = 1
            optLabel.Position = UDim2.new(0, 14, 0, 0)
            optLabel.Size = UDim2.new(1, -24, 1, 0)
            optLabel.FontFace = FONT
            optLabel.TextSize = 13
            optLabel.TextColor3 = PALETTE.text
            optLabel.TextXAlignment = Enum.TextXAlignment.Left
            optLabel.TextTruncate = Enum.TextTruncate.AtEnd
            optLabel.Text = tostring(opt)
            optLabel.Parent = optBtn

            local refs = { btn = optBtn, label = optLabel, on = false }
            optRows[opt] = refs
            paint(refs, opt)
            optBtn.MouseEnter:Connect(function()
                if not refs.on then tween(optBtn, 0.1, { BackgroundTransparency = 0.5, BackgroundColor3 = PALETTE.controlHover }) end
            end)
            optBtn.MouseLeave:Connect(function()
                if not refs.on then tween(optBtn, 0.1, { BackgroundTransparency = 1 }) end
            end)
            optBtn.MouseButton1Click:Connect(function()
                if multi then
                    selected[opt] = not selected[opt] or nil
                    paint(refs, opt)
                    local list = {}
                    for _, o in ipairs(getOptions()) do if selected[o] then table.insert(list, o) end end
                    set(list)
                    button.Text = labelText()
                else
                    set(opt)
                    button.Text = tostring(opt)
                    panel:Destroy()
                    panel = nil
                end
            end)
        end

        if searchBox then
            searchBox:GetPropertyChangedSignal("Text"):Connect(function()
                local q = searchBox.Text:lower()
                for opt, refs in pairs(optRows) do
                    refs.btn.Visible = q == "" or tostring(opt):lower():find(q, 1, true) ~= nil
                end
            end)
        end
    end)
    return row
end

function Controls.colorpicker(parent, ctx, text, getRgb, setRgb, opts)
    local row = controlRow(parent, 30)
    rowLabel(row, text, 120)
    -- Alpha (opacity) is shown by default; pass opts.alpha = false to hide it. When
    -- shown, the value is { r, g, b, a } with a in 0..1 (scripts reading r,g,b still work).
    local useAlpha = not (opts and opts.alpha == false)
    local alpha = useAlpha and ((getRgb() or {})[4] or 1) or 1

    local function hexOf(rgb)
        return string.format("#%02X%02X%02X", rgb[1] or 0, rgb[2] or 0, rgb[3] or 0)
    end

    -- Palette icon button on the far right (samet style).
    local pipette = Instance.new("TextButton")
    pipette.AnchorPoint = Vector2.new(1, 0.5)
    pipette.Position = UDim2.new(1, 0, 0.5, 0)
    pipette.Size = UDim2.new(0, 24, 0, 24)
    pipette.BackgroundTransparency = 1
    pipette.AutoButtonColor = false
    pipette.Text = ""
    pipette.Parent = row
    local palImg = makeIcon(pipette, "palette", UDim2.new(1, 0, 1, 0), PALETTE.text)
    palImg.Active = false

    local hexLabel = Instance.new("TextLabel")
    hexLabel.AnchorPoint = Vector2.new(1, 0.5)
    hexLabel.Position = UDim2.new(1, -30, 0.5, 0)
    hexLabel.Size = UDim2.new(0, 72, 0, 20)
    hexLabel.BackgroundTransparency = 1
    hexLabel.FontFace = FONT
    hexLabel.TextSize = 14
    hexLabel.TextColor3 = PALETTE.text
    hexLabel.TextXAlignment = Enum.TextXAlignment.Right
    hexLabel.Text = hexOf(getRgb())
    hexLabel.Parent = row

    -- Round colour swatch to the left of the hex value.
    local swatch = Instance.new("TextButton")
    swatch.AnchorPoint = Vector2.new(1, 0.5)
    swatch.Position = UDim2.new(1, -108, 0.5, 0)
    swatch.Size = UDim2.new(0, 18, 0, 18)
    swatch.BackgroundColor3 = colorOf(getRgb())
    swatch.BackgroundTransparency = useAlpha and (1 - alpha) or 0
    swatch.BorderSizePixel = 0
    swatch.AutoButtonColor = false
    swatch.Text = ""
    swatch.Active = false
    swatch.Parent = row
    corner(swatch, 9)
    stroke(swatch, PALETTE.stroke, 1, 0.2)

    local panel
    local h, s, v = colorOf(getRgb()):ToHSV()
    local function openPicker()
        if panel and panel.Parent then panel:Destroy() panel = nil return end
        if ctx.closeOverlays then ctx.closeOverlays() end
        if ctx.showBackdrop then ctx.showBackdrop() end
        panel = Instance.new("Frame")
        panel.BackgroundColor3 = PALETTE.card
        panel.BorderSizePixel = 0
        panel.ZIndex = 60
        local panelH = useAlpha and 226 or 196
        panel.Size = UDim2.new(0, 232, 0, panelH)
        local cx = swatch.AbsolutePosition.X - ctx.window.AbsolutePosition.X - 190
        local cy = swatch.AbsolutePosition.Y - ctx.window.AbsolutePosition.Y + 26
        panel.Position = ctx.fitPanel and ctx.fitPanel(cx, cy, 232, panelH) or UDim2.new(0, cx, 0, cy)
        panel.Parent = ctx.overlay
        corner(panel, 10)
        stroke(panel, PALETTE.stroke, 1, 0.2)
        padding(panel, 12)

        local sv = Instance.new("ImageButton")
        sv.Size = UDim2.new(1, -32, 0, 138)
        sv.BackgroundColor3 = Color3.fromHSV(h, 1, 1)
        sv.AutoButtonColor = false
        sv.BorderSizePixel = 0
        sv.Parent = panel
        corner(sv, 4)
        local satGrad = Instance.new("Frame")
        satGrad.Size = UDim2.new(1, 0, 1, 0)
        satGrad.BackgroundColor3 = Color3.new(1, 1, 1)
        satGrad.BorderSizePixel = 0
        satGrad.Parent = sv
        corner(satGrad, 4)
        local g1 = Instance.new("UIGradient")
        g1.Transparency = NumberSequence.new({ NumberSequenceKeypoint.new(0, 0), NumberSequenceKeypoint.new(1, 1) })
        g1.Parent = satGrad
        local valGrad = Instance.new("Frame")
        valGrad.Size = UDim2.new(1, 0, 1, 0)
        valGrad.BackgroundColor3 = Color3.new(0, 0, 0)
        valGrad.BorderSizePixel = 0
        valGrad.Parent = sv
        corner(valGrad, 4)
        local g2 = Instance.new("UIGradient")
        g2.Rotation = 90
        g2.Transparency = NumberSequence.new({ NumberSequenceKeypoint.new(0, 1), NumberSequenceKeypoint.new(1, 0) })
        g2.Parent = valGrad

        local hue = Instance.new("ImageButton")
        hue.AnchorPoint = Vector2.new(1, 0)
        hue.Position = UDim2.new(1, 0, 0, 0)
        hue.Size = UDim2.new(0, 22, 0, 138)
        hue.AutoButtonColor = false
        hue.BorderSizePixel = 0
        hue.Parent = panel
        corner(hue, 4)
        local hueGrad = Instance.new("UIGradient")
        hueGrad.Rotation = 90
        hueGrad.Color = ColorSequence.new({
            ColorSequenceKeypoint.new(0, Color3.fromHSV(0, 1, 1)),
            ColorSequenceKeypoint.new(0.17, Color3.fromHSV(0.17, 1, 1)),
            ColorSequenceKeypoint.new(0.33, Color3.fromHSV(0.33, 1, 1)),
            ColorSequenceKeypoint.new(0.5, Color3.fromHSV(0.5, 1, 1)),
            ColorSequenceKeypoint.new(0.67, Color3.fromHSV(0.67, 1, 1)),
            ColorSequenceKeypoint.new(0.83, Color3.fromHSV(0.83, 1, 1)),
            ColorSequenceKeypoint.new(1, Color3.fromHSV(1, 1, 1)),
        })
        hueGrad.Parent = hue

        -- Cursor indicators.
        local svCursor = Instance.new("Frame")
        svCursor.AnchorPoint = Vector2.new(0.5, 0.5)
        svCursor.Size = UDim2.new(0, 10, 0, 10)
        svCursor.Position = UDim2.new(s, 0, 1 - v, 0)
        svCursor.BackgroundColor3 = Color3.new(1, 1, 1)
        svCursor.BorderSizePixel = 0
        svCursor.ZIndex = 5
        svCursor.Parent = sv
        corner(svCursor, 5)
        stroke(svCursor, Color3.fromRGB(0, 0, 0), 1.5, 0.3)

        local hueCursor = Instance.new("Frame")
        hueCursor.AnchorPoint = Vector2.new(0.5, 0.5)
        hueCursor.Size = UDim2.new(1, 4, 0, 4)
        hueCursor.Position = UDim2.new(0.5, 0, h, 0)
        hueCursor.BackgroundColor3 = Color3.new(1, 1, 1)
        hueCursor.BorderSizePixel = 0
        hueCursor.ZIndex = 5
        hueCursor.Parent = hue
        corner(hueCursor, 2)
        stroke(hueCursor, Color3.fromRGB(0, 0, 0), 1, 0.4)

        -- Opacity (alpha) bar below the SV box.
        local alphaBar, alphaCursor
        if useAlpha then
            alphaBar = Instance.new("ImageButton")
            alphaBar.Position = UDim2.new(0, 0, 0, 150)
            alphaBar.Size = UDim2.new(1, 0, 0, 16)
            alphaBar.BackgroundColor3 = colorOf(getRgb())
            alphaBar.AutoButtonColor = false
            alphaBar.BorderSizePixel = 0
            alphaBar.Parent = panel
            corner(alphaBar, 4)
            local aGrad = Instance.new("UIGradient")
            aGrad.Transparency = NumberSequence.new({ NumberSequenceKeypoint.new(0, 1), NumberSequenceKeypoint.new(1, 0) })
            aGrad.Parent = alphaBar
            alphaCursor = Instance.new("Frame")
            alphaCursor.AnchorPoint = Vector2.new(0.5, 0.5)
            alphaCursor.Size = UDim2.new(0, 4, 1, 4)
            alphaCursor.Position = UDim2.new(alpha, 0, 0.5, 0)
            alphaCursor.BackgroundColor3 = Color3.new(1, 1, 1)
            alphaCursor.BorderSizePixel = 0
            alphaCursor.ZIndex = 5
            alphaCursor.Parent = alphaBar
            corner(alphaCursor, 2)
            stroke(alphaCursor, Color3.fromRGB(0, 0, 0), 1, 0.4)
        end

        local hexBox
        local function apply()
            sv.BackgroundColor3 = Color3.fromHSV(h, 1, 1)
            local final = Color3.fromHSV(h, s, v)
            swatch.BackgroundColor3 = final
            svCursor.Position = UDim2.new(s, 0, 1 - v, 0)
            hueCursor.Position = UDim2.new(0.5, 0, h, 0)
            local rgb = { math.floor(final.R * 255 + 0.5), math.floor(final.G * 255 + 0.5), math.floor(final.B * 255 + 0.5) }
            hexLabel.Text = hexOf(rgb)
            if hexBox then hexBox.Text = hexOf(rgb) end
            if useAlpha then
                alphaBar.BackgroundColor3 = final
                alphaCursor.Position = UDim2.new(alpha, 0, 0.5, 0)
                swatch.BackgroundTransparency = 1 - alpha
                rgb[4] = alpha
            end
            setRgb(rgb)
        end
        local dragSV, dragHue, dragAlpha = false, false, false
        local function updSV(x, y)
            s = math.clamp((x - sv.AbsolutePosition.X) / math.max(sv.AbsoluteSize.X, 1), 0, 1)
            v = 1 - math.clamp((y - sv.AbsolutePosition.Y) / math.max(sv.AbsoluteSize.Y, 1), 0, 1)
            apply()
        end
        local function updHue(y)
            h = math.clamp((y - hue.AbsolutePosition.Y) / math.max(hue.AbsoluteSize.Y, 1), 0, 1)
            apply()
        end
        local function updAlpha(x)
            alpha = math.clamp((x - alphaBar.AbsolutePosition.X) / math.max(alphaBar.AbsoluteSize.X, 1), 0, 1)
            apply()
        end
        sv.InputBegan:Connect(function(i) if i.UserInputType == Enum.UserInputType.MouseButton1 then dragSV = true updSV(i.Position.X, i.Position.Y) end end)
        hue.InputBegan:Connect(function(i) if i.UserInputType == Enum.UserInputType.MouseButton1 then dragHue = true updHue(i.Position.Y) end end)
        if useAlpha then
            alphaBar.InputBegan:Connect(function(i) if i.UserInputType == Enum.UserInputType.MouseButton1 then dragAlpha = true updAlpha(i.Position.X) end end)
        end
        UserInputService.InputChanged:Connect(function(i)
            if i.UserInputType == Enum.UserInputType.MouseMovement then
                if dragSV then updSV(i.Position.X, i.Position.Y)
                elseif dragHue then updHue(i.Position.Y)
                elseif dragAlpha then updAlpha(i.Position.X) end
            end
        end)
        UserInputService.InputEnded:Connect(function(i)
            if i.UserInputType == Enum.UserInputType.MouseButton1 then dragSV = false dragHue = false dragAlpha = false end
        end)

        hexBox = Instance.new("TextBox")
        hexBox.AnchorPoint = Vector2.new(0, 1)
        hexBox.Position = UDim2.new(0, 0, 1, 0)
        hexBox.Size = UDim2.new(1, 0, 0, 28)
        hexBox.BackgroundColor3 = PALETTE.control
        hexBox.BorderSizePixel = 0
        hexBox.FontFace = FONT
        hexBox.TextSize = 14
        hexBox.TextColor3 = PALETTE.text
        hexBox.PlaceholderColor3 = PALETTE.subtext
        hexBox.PlaceholderText = "#RRGGBB"
        hexBox.Text = hexLabel.Text
        hexBox.ClearTextOnFocus = false
        hexBox.Parent = panel
        corner(hexBox, 6)
        hexBox.FocusLost:Connect(function()
            local hx = string.gsub(hexBox.Text, "#", "")
            if #hx == 6 then
                local r = tonumber(string.sub(hx, 1, 2), 16)
                local g = tonumber(string.sub(hx, 3, 4), 16)
                local b = tonumber(string.sub(hx, 5, 6), 16)
                if r and g and b then
                    h, s, v = Color3.fromRGB(r, g, b):ToHSV()
                    apply()
                    return
                end
            end
            hexBox.Text = hexLabel.Text
        end)
    end
    pipette.MouseButton1Click:Connect(openPicker)
    pipette.MouseEnter:Connect(function() tintIcon(palImg, PALETTE.accent) end)
    pipette.MouseLeave:Connect(function() tintIcon(palImg, PALETTE.text) end)
    -- Keep the swatch and hex in sync when the value changes externally (theme reset).
    if ctx and ctx._refresh then
        table.insert(ctx._refresh, function()
            local c = colorOf(getRgb())
            swatch.BackgroundColor3 = c
            hexLabel.Text = hexOf(getRgb())
            h, s, v = c:ToHSV()
            if useAlpha then
                alpha = (getRgb() or {})[4] or alpha
                swatch.BackgroundTransparency = 1 - alpha
            end
        end)
    end
    return row
end

-- Segmented control: a row of mutually exclusive pills (Toggle / Hold / Always).
function Controls.segmented(parent, ctx, text, options, get, set)
    local row = controlRow(parent, 30)
    if text and text ~= "" then
        rowLabel(row, text, 200)
    end
    local holder = Instance.new("Frame")
    holder.AnchorPoint = Vector2.new(1, 0.5)
    holder.Position = UDim2.new(1, 0, 0.5, 0)
    holder.Size = UDim2.new(0, math.min(60 * #options, 220), 1, -4)
    holder.BackgroundTransparency = 1
    holder.Parent = row
    listLayout(holder, 6, Enum.FillDirection.Horizontal)
    local buttons = {}
    local function render()
        local current = get()
        for value, btn in pairs(buttons) do
            local on = value == current
            tween(btn, 0.14, { BackgroundColor3 = on and PALETTE.accent or PALETTE.control })
            btn.TextColor3 = PALETTE.text
        end
    end
    for _, option in ipairs(options) do
        local btn = Instance.new("TextButton")
        btn.Size = UDim2.new(0, 54, 1, 0)
        btn.BackgroundColor3 = PALETTE.control
        btn.BorderSizePixel = 0
        btn.AutoButtonColor = false
        btn.FontFace = FONT
        btn.TextSize = 13
        btn.Text = tostring(option)
        btn.Parent = holder
        corner(btn, 6)
        buttons[option] = btn
        btn.MouseButton1Click:Connect(function()
            set(option)
            render()
        end)
    end
    render()
    if ctx and ctx._refresh then table.insert(ctx._refresh, render) end
    return row
end

-- Inline searchable list with radio selection (single choice).
function Controls.list(parent, ctx, options, get, set, opts)
    opts = opts or {}
    local container = Instance.new("Frame")
    container.Size = UDim2.new(1, 0, 0, 0)
    container.AutomaticSize = Enum.AutomaticSize.Y
    container.BackgroundTransparency = 1
    container.LayoutOrder = nextOrder(parent)
    container.Parent = parent
    listLayout(container, 4)

    local rows = {}
    local searchBox
    if opts.search ~= false then
        local search = Instance.new("Frame")
        search.Size = UDim2.new(1, 0, 0, 30)
        search.BackgroundColor3 = PALETTE.control
        search.BorderSizePixel = 0
        search.LayoutOrder = nextOrder(container)
        search.Parent = container
        corner(search, 8)
        local sicon = makeIcon(search, "search", UDim2.new(0, 15, 0, 15), PALETTE.subtext)
        sicon.AnchorPoint = Vector2.new(0, 0.5)
        sicon.Position = UDim2.new(0, 10, 0.5, 0)
        searchBox = Instance.new("TextBox")
        searchBox.BackgroundTransparency = 1
        searchBox.Position = UDim2.new(0, 32, 0, 0)
        searchBox.Size = UDim2.new(1, -42, 1, 0)
        searchBox.FontFace = FONT
        searchBox.TextSize = 13
        searchBox.TextColor3 = PALETTE.text
        searchBox.PlaceholderColor3 = PALETTE.subtext
        searchBox.PlaceholderText = "Search.."
        searchBox.Text = ""
        searchBox.ClearTextOnFocus = false
        searchBox.TextXAlignment = Enum.TextXAlignment.Left
        searchBox.Parent = search
    end

    local function render()
        local current = get()
        for value, refs in pairs(rows) do
            local on = value == current
            refs.label.TextColor3 = on and PALETTE.accent or PALETTE.text
            refs.row.BackgroundColor3 = PALETTE.controlHover
            refs.row.BackgroundTransparency = on and 0 or 1
            refs.on = on
        end
    end
    for _, option in ipairs(options) do
        local optRow = Instance.new("TextButton")
        optRow.Size = UDim2.new(1, 0, 0, 32)
        optRow.BackgroundColor3 = PALETTE.controlHover
        optRow.BackgroundTransparency = 1
        optRow.AutoButtonColor = false
        optRow.Text = ""
        optRow.LayoutOrder = nextOrder(container)
        optRow.Parent = container
        corner(optRow, 8)
        local label = Instance.new("TextLabel")
        label.BackgroundTransparency = 1
        label.Position = UDim2.new(0, 14, 0, 0)
        label.Size = UDim2.new(1, -24, 1, 0)
        label.FontFace = FONT
        label.TextSize = 14
        label.TextColor3 = PALETTE.text
        label.TextXAlignment = Enum.TextXAlignment.Left
        label.TextTruncate = Enum.TextTruncate.AtEnd
        label.Text = tostring(option)
        label.Parent = optRow
        rows[option] = { label = label, row = optRow, on = false }
        optRow.MouseEnter:Connect(function()
            if get() ~= option then
                tween(optRow, 0.1, { BackgroundTransparency = 0.5, BackgroundColor3 = PALETTE.controlHover })
            end
        end)
        optRow.MouseLeave:Connect(function()
            if get() ~= option then
                tween(optRow, 0.1, { BackgroundTransparency = 1 })
            end
        end)
        optRow.MouseButton1Click:Connect(function()
            set(option)
            render()
        end)
    end
    render()
    if ctx and ctx._refresh then table.insert(ctx._refresh, render) end
    if searchBox then
        searchBox:GetPropertyChangedSignal("Text"):Connect(function()
            local q = searchBox.Text:lower()
            for opt, refs in pairs(rows) do
                refs.row.Visible = q == "" or tostring(opt):lower():find(q, 1, true) ~= nil
            end
        end)
    end
    return container
end

-- Stepper: a numeric value with minus and plus buttons (- value +).
function Controls.stepper(parent, ctx, text, min, max, step, get, set)
    step = step or 1
    local row = controlRow(parent, 30)
    rowLabel(row, text, 110)

    local holder = Instance.new("Frame")
    holder.AnchorPoint = Vector2.new(1, 0.5)
    holder.Position = UDim2.new(1, 0, 0.5, 0)
    holder.Size = UDim2.new(0, 100, 0, 24)
    themed(holder, "BackgroundColor3", "control")
    holder.BorderSizePixel = 0
    holder.Parent = row
    corner(holder, 6)

    local function mkArrow(symbol, x, anchorX)
        local b = Instance.new("TextButton")
        b.AnchorPoint = Vector2.new(anchorX, 0.5)
        b.Position = UDim2.new(x, 0, 0.5, 0)
        b.Size = UDim2.new(0, 26, 1, 0)
        b.BackgroundTransparency = 1
        b.AutoButtonColor = false
        b.FontFace = FONT
        b.TextSize = 18
        b.TextColor3 = PALETTE.subtext
        b.Text = symbol
        b.Parent = holder
        b.MouseEnter:Connect(function() b.TextColor3 = PALETTE.accent end)
        b.MouseLeave:Connect(function() b.TextColor3 = PALETTE.subtext end)
        return b
    end
    local minus = mkArrow("-", 0, 0)
    local plus = mkArrow("+", 1, 1)

    local value = Instance.new("TextBox")
    value.AnchorPoint = Vector2.new(0.5, 0.5)
    value.Position = UDim2.new(0.5, 0, 0.5, 0)
    value.Size = UDim2.new(0, 48, 1, 0)
    value.BackgroundTransparency = 1
    value.FontFace = FONT
    value.TextSize = 14
    value.TextColor3 = PALETTE.text
    value.Text = tostring(get())
    value.ClearTextOnFocus = false
    value.TextXAlignment = Enum.TextXAlignment.Center
    value.Parent = holder

    local function apply(v)
        v = math.clamp(v, min, max)
        set(v)
        value.Text = tostring(v)
    end
    minus.MouseButton1Click:Connect(function() apply(get() - step) end)
    plus.MouseButton1Click:Connect(function() apply(get() + step) end)
    value.FocusLost:Connect(function()
        local typed = tonumber(string.match(value.Text, "[%-%d%.]+"))
        if typed then apply(typed) else value.Text = tostring(get()) end
    end)
    if ctx and ctx._refresh then table.insert(ctx._refresh, function() value.Text = tostring(get()) end) end
    return row
end
-- and owning window as context.
Card = {}
Card.__index = Card
function Card.new(frame, ctx)
    return setmetatable({ _frame = frame, _ctx = ctx }, Card)
end
function Card:label(text) return Controls.label(self._frame, text) end
function Card:button(text, fn) return Controls.button(self._frame, self._ctx, text, fn) end
function Card:input(text, placeholder, get, set) return Controls.input(self._frame, self._ctx, text, placeholder, get, set) end
function Card:toggle(text, get, set, settings) return Controls.toggle(self._frame, self._ctx, text, get, set, settings) end
function Card:slider(text, min, max, get, set, decimals, format) return Controls.slider(self._frame, self._ctx, text, min, max, get, set, decimals, format) end
function Card:keybind(text, getKey, setKey, opts) return Controls.keybind(self._frame, self._ctx, text, getKey, setKey, opts) end
function Card:dropdown(text, options, get, set, opts) return Controls.dropdown(self._frame, self._ctx, text, options, get, set, opts) end
function Card:colorpicker(text, getRgb, setRgb, opts) return Controls.colorpicker(self._frame, self._ctx, text, getRgb, setRgb, opts) end
function Card:segmented(text, options, get, set) return Controls.segmented(self._frame, self._ctx, text, options, get, set) end
function Card:list(options, get, set, opts) return Controls.list(self._frame, self._ctx, options, get, set, opts) end
function Card:stepper(text, min, max, step, get, set) return Controls.stepper(self._frame, self._ctx, text, min, max, step, get, set) end
-- A thin divider line inside a card body.
function Card:divider()
    local line = Instance.new("Frame")
    line.Size = UDim2.new(1, 0, 0, 1)
    line.BackgroundColor3 = PALETTE.stroke
    line.BackgroundTransparency = 0.4
    line.BorderSizePixel = 0
    line.LayoutOrder = nextOrder(self._frame)
    line.Parent = self._frame
    return line
end

-- Sub-tab page: two scrolling columns that hold cards.
local Sub = {}
Sub.__index = Sub
function Sub.new(page, ctx, left, right)
    return setmetatable({ _page = page, _ctx = ctx, left = left, right = right }, Sub)
end
function Sub:card(title, column)
    -- Accept either card("Title", "left") or card({ title=, subtitle=, icon=, toggle={get,set}, column= }).
    local cfg
    if type(title) == "table" then
        cfg = title
    else
        cfg = { title = title, column = column }
    end
    local col = (cfg.column == "right") and self.right or self.left

    local cardFrame = Instance.new("Frame")
    cardFrame.Size = UDim2.new(1, 0, 0, 0)
    cardFrame.AutomaticSize = Enum.AutomaticSize.Y
    themed(cardFrame, "BackgroundColor3", "card")
    cardFrame.BorderSizePixel = 0
    cardFrame.LayoutOrder = nextOrder(col)
    cardFrame.Parent = col
    corner(cardFrame, 12)
    stroke(cardFrame, PALETTE.stroke, 1, 0.4)

    local body = Instance.new("Frame")
    body.BackgroundTransparency = 1
    body.Size = UDim2.new(1, 0, 0, 0)
    body.AutomaticSize = Enum.AutomaticSize.Y
    body.Parent = cardFrame
    listLayout(body, 11)
    padding(body, 16)

    if cfg.title then
        -- Header row: optional icon, title with optional subtitle, optional enable toggle.
        local header = Instance.new("Frame")
        header.Size = UDim2.new(1, 0, 0, cfg.subtitle and 36 or 20)
        header.BackgroundTransparency = 1
        header.LayoutOrder = nextOrder(body)
        header.Parent = body

        local textX = 0
        if cfg.icon then
            local hicon = makeIcon(header, cfg.icon, UDim2.new(0, 26, 0, 26), PALETTE.text)
            hicon.AnchorPoint = Vector2.new(0, 0.5)
            hicon.Position = UDim2.new(0, 0, 0.5, 0)
            textX = 36
        end

        local titleLabel = Instance.new("TextLabel")
        titleLabel.BackgroundTransparency = 1
        titleLabel.Position = UDim2.new(0, textX, 0, 0)
        titleLabel.Size = UDim2.new(1, -textX - (cfg.toggle and 54 or 0), 0, 20)
        titleLabel.FontFace = FONT
        titleLabel.TextSize = 17
        titleLabel.TextColor3 = PALETTE.text
        titleLabel.TextXAlignment = Enum.TextXAlignment.Left
        titleLabel.TextYAlignment = cfg.subtitle and Enum.TextYAlignment.Top or Enum.TextYAlignment.Center
        titleLabel.Text = cfg.title
        titleLabel.Parent = header

        if cfg.subtitle then
            local subLabel = Instance.new("TextLabel")
            subLabel.BackgroundTransparency = 1
            subLabel.Position = UDim2.new(0, textX, 0, 20)
            subLabel.Size = UDim2.new(1, -textX - (cfg.toggle and 54 or 0), 0, 16)
            subLabel.FontFace = FONT
            subLabel.TextSize = 12
            subLabel.TextColor3 = PALETTE.subtext
            subLabel.TextXAlignment = Enum.TextXAlignment.Left
            subLabel.Text = cfg.subtitle
            subLabel.Parent = header
        end

        if cfg.toggle then
            makePill(header, self._ctx, cfg.toggle.get, cfg.toggle.set)
        end

        -- Divider under the header to separate it from the controls.
        local line = Instance.new("Frame")
        line.Size = UDim2.new(1, 0, 0, 1)
        line.BackgroundColor3 = PALETTE.stroke
        line.BackgroundTransparency = 0.4
        line.BorderSizePixel = 0
        line.LayoutOrder = nextOrder(body)
        line.Parent = body
    end
    return Card.new(body, self._ctx)
end

-- Tab: a sidebar entry that owns a top sub-tab bar and sub-pages.
local Tab = {}
Tab.__index = Tab
function Tab:sub(name)
    local order = #self._subs + 1
    local btn = Instance.new("TextButton")
    btn.AutomaticSize = Enum.AutomaticSize.X
    btn.Size = UDim2.new(0, 0, 1, 0)
    btn.BackgroundTransparency = 1
    btn.AutoButtonColor = false
    btn.FontFace = FONT
    btn.TextSize = 15
    btn.TextColor3 = PALETTE.subtext
    btn.Text = name
    btn.LayoutOrder = order
    btn.Parent = self._subBar
    local bpad = Instance.new("UIPadding")
    bpad.PaddingLeft = UDim.new(0, 2)
    bpad.PaddingRight = UDim.new(0, 2)
    bpad.Parent = btn

    local underline = Instance.new("Frame")
    underline.AnchorPoint = Vector2.new(0, 1)
    underline.Position = UDim2.new(0, 0, 1, 0)
    underline.Size = UDim2.new(1, 0, 0, 2)
    themed(underline, "BackgroundColor3", "accent")
    underline.BorderSizePixel = 0
    underline.Visible = false
    underline.Parent = btn

    local page = Instance.new("CanvasGroup")
    page.Size = UDim2.new(1, 0, 1, 0)
    page.BackgroundTransparency = 1
    page.BorderSizePixel = 0
    page.Visible = false
    page.Parent = self._subPages
    local columns = Instance.new("Frame")
    columns.BackgroundTransparency = 1
    columns.Size = UDim2.new(1, 0, 1, 0)
    columns.Parent = page
    local function makeColumn(nm, x)
        local sf = Instance.new("ScrollingFrame")
        sf.Name = nm
        sf.Size = UDim2.new(0.5, -8, 1, 0)
        sf.Position = UDim2.new(x, x == 0 and 0 or 8, 0, 0)
        sf.BackgroundTransparency = 1
        sf.BorderSizePixel = 0
        sf.ScrollBarThickness = 0
        sf.ScrollingDirection = Enum.ScrollingDirection.Y
        sf.CanvasSize = UDim2.new(0, 0, 0, 0)
        sf.AutomaticCanvasSize = Enum.AutomaticSize.Y
        sf.Parent = columns
        listLayout(sf, 12)
        local pad = Instance.new("UIPadding")
        pad.PaddingBottom = UDim.new(0, 10)
        pad.PaddingTop = UDim.new(0, 2)
        pad.Parent = sf
        return sf
    end
    local leftCol = makeColumn("Left", 0)
    local rightCol = makeColumn("Right", 0.5)

    local sub = { name = name, btn = btn, underline = underline, page = page }
    table.insert(self._subs, sub)

    local function activate()
        for _, other in ipairs(self._subs) do
            other.page.Visible = false
            other.underline.Visible = false
            tween(other.btn, 0.15, { TextColor3 = PALETTE.subtext })
        end
        if self._ctx.closeOverlays then self._ctx.closeOverlays() end
        page.Visible = true
        page.GroupTransparency = 1
        tween(page, 0.2, { GroupTransparency = 0 })
        underline.Visible = true
        tween(btn, 0.15, { TextColor3 = PALETTE.text })
    end
    btn.MouseButton1Click:Connect(activate)
    if #self._subs == 1 then
        activate()
    end
    return Sub.new(page, self._ctx, leftCol, rightCol)
end

local Window = {}
Window.__index = Window

function Window:tab(opts)
    opts = opts or {}
    local groupName = opts.group
    if groupName and not self.groups[groupName] then
        local header = Instance.new("TextLabel")
        header.BackgroundTransparency = 1
        header.Size = UDim2.new(1, 0, 0, 22)
        header.FontFace = FONT
        header.TextSize = 12
        header.TextColor3 = PALETTE.subtext
        header.TextXAlignment = Enum.TextXAlignment.Left
        header.Text = string.upper(groupName)
        header.LayoutOrder = nextOrder(self.sidebarList)
        header.Parent = self.sidebarList
        local hpad = Instance.new("UIPadding")
        hpad.PaddingLeft = UDim.new(0, 12)
        hpad.PaddingTop = UDim.new(0, 8)
        hpad.Parent = header
        self.groups[groupName] = true
    end

    local btn = Instance.new("TextButton")
    btn.Size = UDim2.new(1, 0, 0, 38)
    themed(btn, "BackgroundColor3", "control")
    btn.BackgroundTransparency = 1
    btn.AutoButtonColor = false
    btn.Text = ""
    btn.BorderSizePixel = 0
    btn.LayoutOrder = nextOrder(self.sidebarList)
    btn.Parent = self.sidebarList
    corner(btn, 8)

    local icon = makeIcon(btn, opts.icon, UDim2.new(0, 24, 0, 24), PALETTE.text)
    icon.AnchorPoint = Vector2.new(0, 0.5)
    icon.Position = UDim2.new(0, 14, 0.5, 0)

    -- Left accent bar shown only on the active tab.
    local indicator = Instance.new("Frame")
    indicator.AnchorPoint = Vector2.new(0, 0.5)
    indicator.Position = UDim2.new(0, 0, 0.5, 0)
    indicator.Size = UDim2.new(0, 3, 0, 0)
    themed(indicator, "BackgroundColor3", "accent")
    indicator.BorderSizePixel = 0
    indicator.Parent = btn
    corner(indicator, 2)

    local label = Instance.new("TextLabel")
    label.BackgroundTransparency = 1
    label.Position = UDim2.new(0, 48, 0, 0)
    label.Size = UDim2.new(1, -56, 1, 0)
    label.FontFace = FONT
    label.TextSize = 15
    label.TextColor3 = PALETTE.subtext
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Text = opts.name
    label.Parent = btn

    local tabPage = Instance.new("CanvasGroup")
    tabPage.Size = UDim2.new(1, 0, 1, 0)
    tabPage.BackgroundTransparency = 1
    tabPage.BorderSizePixel = 0
    tabPage.Visible = false
    tabPage.Parent = self.pages

    local subBar = Instance.new("Frame")
    subBar.Size = UDim2.new(1, 0, 0, 30)
    subBar.BackgroundTransparency = 1
    subBar.Parent = tabPage
    listLayout(subBar, 16, Enum.FillDirection.Horizontal)
    local subDivider = Instance.new("Frame")
    subDivider.Position = UDim2.new(0, 0, 0, 34)
    subDivider.Size = UDim2.new(1, 0, 0, 1)
    subDivider.BackgroundColor3 = PALETTE.stroke
    subDivider.BackgroundTransparency = 0.3
    subDivider.BorderSizePixel = 0
    subDivider.Parent = tabPage

    local subPages = Instance.new("Frame")
    subPages.Position = UDim2.new(0, 0, 0, 44)
    subPages.Size = UDim2.new(1, 0, 1, -44)
    subPages.BackgroundTransparency = 1
    subPages.Parent = tabPage

    local tabObj = setmetatable({
        _ctx = self, _subBar = subBar, _subPages = subPages, _subs = {},
        name = opts.name, btn = btn, icon = icon, label = label, page = tabPage,
        indicator = indicator,
    }, Tab)
    table.insert(self.tabs, tabObj)

    local function activate()
        for _, other in ipairs(self.tabs) do
            other.page.Visible = false
            tween(other.btn, 0.15, { BackgroundTransparency = 1 })
            tween(other.label, 0.15, { TextColor3 = PALETTE.subtext })
            if other.indicator then
                tween(other.indicator, 0.15, { Size = UDim2.new(0, 3, 0, 0) })
            end
        end
        if self.closeOverlays then self.closeOverlays() end
        tabPage.Visible = true
        tabPage.GroupTransparency = 1
        tabPage.Position = UDim2.new(0, 0, 0, 12)
        tween(tabPage, 0.22, { GroupTransparency = 0, Position = UDim2.new(0, 0, 0, 0) })
        tween(btn, 0.15, { BackgroundTransparency = 0 })
        tween(label, 0.15, { TextColor3 = PALETTE.text })
        tween(indicator, 0.2, { Size = UDim2.new(0, 3, 0, 20) }, Enum.EasingStyle.Back)
        self.title.Text = opts.name
        if self.subtitle then
            self.subtitle.Text = opts.subtitle or opts.group or ""
        end
    end
    btn.MouseButton1Click:Connect(activate)
    btn.MouseEnter:Connect(function()
        if not tabPage.Visible then tween(btn, 0.12, { BackgroundTransparency = 0.6 }) end
    end)
    btn.MouseLeave:Connect(function()
        if not tabPage.Visible then tween(btn, 0.12, { BackgroundTransparency = 1 }) end
    end)
    if #self.tabs == 1 then
        activate()
    end
    return tabObj
end

function Window:toggle()
    self.window.Visible = not self.window.Visible
end

-- Recolour every part that follows this palette key, then refresh the dynamic
-- controls (toggles, segmented, lists) that pick colours at runtime.
--
-- Two paths are used. Tagged parts (themed(...)) are matched by their nrK key.
-- Untagged parts painted straight from the palette are matched by their current
-- colour, but only when that colour is unique in the palette, so keys that share
-- a colour (e.g. track and controlHover) never bleed into one another.
function Window:setColor(key, rgb)
    local old = PALETTE[key]
    local new = (typeof(rgb) == "Color3") and rgb or colorOf(rgb)
    local alpha = (type(rgb) == "table" and rgb[4]) or PALETTE_A[key] or 1
    PALETTE[key] = new
    PALETTE_A[key] = alpha

    local unique = true
    for k, c in pairs(PALETTE) do
        if k ~= key and c == old then unique = false break end
    end

    -- Map the key's alpha onto a part's transparency. The part's own original
    -- transparency is remembered once so a return to full opacity restores it,
    -- and parts that are fully hidden stay hidden.
    local function applyAlpha(d, prop)
        local tp = TRANS_OF[prop]
        if not tp then return end
        local ok, cur = pcall(function() return d[tp] end)
        if not ok or type(cur) ~= "number" then return end
        local attr = "nrT_" .. tp
        local base = d:GetAttribute(attr)
        if alpha < 1 then
            if base == nil then
                base = cur
                if base < 1 then d:SetAttribute(attr, base) end
            end
            if base >= 1 then return end
            pcall(function() d[tp] = 1 - alpha end)
        elseif base ~= nil then
            pcall(function() d[tp] = base end)
            d:SetAttribute(attr, nil)
        end
    end

    local matchProps = { "BackgroundColor3", "TextColor3", "ImageColor3", "Color" }
    for _, d in ipairs(self.screen:GetDescendants()) do
        local tagged = d:GetAttribute("nrK")
        if tagged == key then
            local prop = d:GetAttribute("nrP")
            pcall(function() d[prop] = new end)
            applyAlpha(d, prop)
        elseif unique and tagged == nil then
            for _, prop in ipairs(matchProps) do
                local ok, cur = pcall(function() return d[prop] end)
                if ok and cur == old then
                    pcall(function() d[prop] = new end)
                    applyAlpha(d, prop)
                end
            end
        end
    end
    if self._refresh then
        for _, fn in ipairs(self._refresh) do pcall(fn) end
    end
end

function Window:getColor(key)
    local c = PALETTE[key]
    return { math.floor(c.R * 255 + 0.5), math.floor(c.G * 255 + 0.5), math.floor(c.B * 255 + 0.5), PALETTE_A[key] or 1 }
end

-- Restore the default palette and full opacity for every key.
function Window:resetTheme()
    for key, def in pairs(DEFAULTS) do
        self:setColor(key, { math.floor(def.R * 255 + 0.5), math.floor(def.G * 255 + 0.5), math.floor(def.B * 255 + 0.5), 1 })
    end
end

-- Re-apply every control's visual from its current value (used after loading a
-- config so toggles, sliders, dropdowns reflect the loaded state).
function Window:refreshAll()
    for _, fn in ipairs(self._refresh) do pcall(fn) end
end

-- Bind a control to a saved flag. Returns get and set backed by window.flags so
-- the value is persisted by save/load. Usage:
--   local g, s = window:flag("aimbot", false); card:toggle("Aimbot", g, s)
function Window:flag(key, default)
    if self.flags[key] == nil then
        self.flags[key] = default
    end
    return function() return self.flags[key] end, function(v) self.flags[key] = v end
end

local CONFIG_ROOT = "NewReality/configs"
-- Configs are stored per game so one game's configs never appear in another.
local function placeFolder()
    -- Key by GameId (universe), not PlaceId, so every place of one game (e.g. a
    -- separate lobby place and the main game place) shares the same configs.
    return CONFIG_ROOT .. "/" .. tostring(game.GameId)
end
local function configPath(name)
    return placeFolder() .. "/" .. name .. ".json"
end
local function ensureConfigDir()
    pcall(function()
        if not (makefolder and isfolder) then return end
        if not isfolder("NewReality") then makefolder("NewReality") end
        if not isfolder(CONFIG_ROOT) then makefolder(CONFIG_ROOT) end
        local d = placeFolder()
        if not isfolder(d) then makefolder(d) end
    end)
end

function Window:saveConfig(name)
    if type(name) ~= "string" or name == "" then return false end
    if type(writefile) ~= "function" then warn("[NewReality] executor has no writefile") return false end
    -- Snapshot the current theme so colours are restored on load too.
    local theme = {}
    for key in pairs(DEFAULTS) do
        local c = PALETTE[key]
        theme[key] = { math.floor(c.R * 255 + 0.5), math.floor(c.G * 255 + 0.5), math.floor(c.B * 255 + 0.5) }
    end
    local payload = { flags = self.flags, theme = theme }
    local ok, err = pcall(function()
        ensureConfigDir()
        writefile(configPath(name), HttpService:JSONEncode(payload))
    end)
    -- Some executors sandbox writefile and silently drop the file without
    -- raising an error, so verify the file is actually present afterwards.
    if ok and type(isfile) == "function" and not isfile(configPath(name)) then
        ok = false
        err = "file missing after write (executor blocked writefile?)"
    end
    if ok then
        print("[NewReality] saved config: " .. configPath(name))
    else
        warn("[NewReality] saveConfig failed: " .. tostring(err))
    end
    return ok
end

function Window:loadConfig(name)
    if type(name) ~= "string" or name == "" then return false end
    if type(readfile) ~= "function" or type(isfile) ~= "function" then
        warn("[NewReality] executor has no readfile/isfile")
        return false
    end
    local path = configPath(name)
    if not isfile(path) then
        warn("[NewReality] config '" .. name .. "' does not exist (" .. path .. ")")
        return false
    end
    local ok, data = pcall(function()
        return HttpService:JSONDecode(readfile(path))
    end)
    if not ok then
        warn("[NewReality] loadConfig failed: " .. tostring(data))
        return false
    end
    if type(data) ~= "table" then return false end
    -- New format is { flags = , theme = }; old format was just the flags table.
    local flags = (type(data.flags) == "table") and data.flags or data
    for k, v in pairs(flags) do self.flags[k] = v end
    -- Restore the saved theme colours by re-tagging every themed element.
    if type(data.theme) == "table" then
        for key, rgb in pairs(data.theme) do
            if DEFAULTS[key] and type(rgb) == "table" then
                PALETTE[key] = colorOf(rgb)
            end
        end
        for _, d in ipairs(self.screen:GetDescendants()) do
            local k = d:GetAttribute("nrK")
            if k and PALETTE[k] then
                local prop = d:GetAttribute("nrP")
                pcall(function() d[prop] = PALETTE[k] end)
            end
        end
    end
    self:refreshAll()
    print("[NewReality] loaded config: " .. path)
    return true
end

function Window:listConfigs()
    local out = {}
    pcall(function()
        local dir = placeFolder()
        if type(listfiles) ~= "function" then return end
        local files = nil
        -- Some executors return isfolder == false even when the folder exists,
        -- so try listfiles directly and fall back to the isfolder guard.
        local ok, res = pcall(listfiles, dir)
        if ok and type(res) == "table" then files = res end
        if files then
            for _, f in ipairs(files) do
                local nm = string.match(f, "([^/\\]+)%.json$")
                if nm then table.insert(out, nm) end
            end
        end
    end)
    return out
end

function Window:deleteConfig(name)
    if type(name) ~= "string" or name == "" then return false end
    if type(delfile) ~= "function" then warn("[NewReality] executor has no delfile") return false end
    local ok, err = pcall(function() delfile(configPath(name)) end)
    if not ok then warn("[NewReality] deleteConfig failed: " .. tostring(err)) end
    return ok
end

-- Auto load pointer: stored in its own file (not inside a config) so it can be
-- read at startup before any config is loaded. setAutoLoad(nil) clears it.
local function autoLoadPath()
    return placeFolder() .. "/_autoload.txt"
end
function Window:setAutoLoad(name)
    local ok = pcall(function()
        ensureConfigDir()
        if type(name) == "string" and name ~= "" then
            if type(writefile) == "function" then writefile(autoLoadPath(), name) end
        elseif type(delfile) == "function" and type(isfile) == "function" and isfile(autoLoadPath()) then
            delfile(autoLoadPath())
        end
    end)
    return ok
end
function Window:getAutoLoad()
    local out = nil
    pcall(function()
        if type(isfile) == "function" and type(readfile) == "function" and isfile(autoLoadPath()) then
            local s = readfile(autoLoadPath())
            if type(s) == "string" and s ~= "" then out = s end
        end
    end)
    return out
end

-- Toast notification, slides in at the bottom right and auto dismisses.
-- Usage: window:notify({ title = "Aimbot", text = "Enabled", duration = 3, icon = "bolt" })
function Window:notify(opts)
    if type(opts) == "string" then opts = { title = opts } end
    opts = opts or {}
    if not self._toasts then
        local holder = Instance.new("Frame")
        holder.Name = "Toasts"
        holder.AnchorPoint = Vector2.new(1, 1)
        holder.Position = UDim2.new(1, -16, 1, -16)
        holder.Size = UDim2.new(0, 290, 1, -32)
        holder.BackgroundTransparency = 1
        holder.ZIndex = 200
        holder.Parent = self.screen
        local l = Instance.new("UIListLayout")
        l.VerticalAlignment = Enum.VerticalAlignment.Bottom
        l.HorizontalAlignment = Enum.HorizontalAlignment.Right
        l.Padding = UDim.new(0, 8)
        l.SortOrder = Enum.SortOrder.LayoutOrder
        l.Parent = holder
        self._toasts = holder
    end

    local toast = Instance.new("CanvasGroup")
    toast.Size = UDim2.new(0, 270, 0, opts.text and 56 or 40)
    toast.BackgroundColor3 = PALETTE.card
    toast.BorderSizePixel = 0
    toast.GroupTransparency = 1
    toast.ZIndex = 200
    toast.Parent = self._toasts
    corner(toast, 10)
    -- Border stroke is not composited by GroupTransparency, so fade it manually.
    local st = stroke(toast, PALETTE.stroke, 1, 1)

    local bar = Instance.new("Frame")
    bar.Size = UDim2.new(0, 4, 1, -16)
    bar.Position = UDim2.new(0, 8, 0, 8)
    bar.BackgroundColor3 = PALETTE.accent
    bar.BorderSizePixel = 0
    bar.Parent = toast
    corner(bar, 2)

    local textX = 22
    if opts.icon then
        local ic = makeIcon(toast, opts.icon, UDim2.new(0, 20, 0, 20), PALETTE.text)
        ic.AnchorPoint = Vector2.new(0, 0.5)
        ic.Position = UDim2.new(0, 22, 0.5, 0)
        textX = 50
    end

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, textX, 0, opts.text and 8 or 0)
    title.Size = UDim2.new(1, -textX - 12, 0, opts.text and 18 or 40)
    title.FontFace = FONT
    title.TextSize = 15
    title.TextColor3 = PALETTE.text
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.TextYAlignment = opts.text and Enum.TextYAlignment.Center or Enum.TextYAlignment.Center
    title.Text = opts.title or "Notification"
    title.Parent = toast

    if opts.text then
        local msg = Instance.new("TextLabel")
        msg.BackgroundTransparency = 1
        msg.Position = UDim2.new(0, textX, 0, 28)
        msg.Size = UDim2.new(1, -textX - 12, 0, 18)
        msg.FontFace = FONT
        msg.TextSize = 13
        msg.TextColor3 = PALETTE.subtext
        msg.TextXAlignment = Enum.TextXAlignment.Left
        msg.TextTruncate = Enum.TextTruncate.AtEnd
        msg.Text = opts.text
        msg.Parent = toast
    end

    tween(toast, 0.2, { GroupTransparency = 0 })
    tween(st, 0.2, { Transparency = 0.3 })
    task.delay(opts.duration or 3, function()
        if toast and toast.Parent then
            tween(st, 0.25, { Transparency = 1 })
            tween(toast, 0.25, { GroupTransparency = 1 }).Completed:Once(function()
                toast:Destroy()
            end)
        end
    end)
    return toast
end

-- Draggable watermark: logo + animated NewReality brand | FPS | time.
-- opts: { position=UDim2, show = { logo=, brand=, fps=, time= } }
function Window:watermark(opts)
    opts = opts or {}
    local show = opts.show or {}
    if self._watermark then self._watermark:Destroy() end

    local wm = Instance.new("Frame")
    wm.Name = "Watermark"
    wm.AutomaticSize = Enum.AutomaticSize.X
    wm.Size = UDim2.new(0, 0, 0, 34)
    wm.Position = opts.position or UDim2.new(0, 16, 0, 16)
    wm.BackgroundColor3 = PALETTE.card
    wm.BorderSizePixel = 0
    wm.ZIndex = 150
    wm.Parent = self.screen
    corner(wm, 8)
    stroke(wm, PALETTE.stroke, 1, 0.3)
    padding(wm, nil, { left = 12, right = 12 })
    local lay = listLayout(wm, 9, Enum.FillDirection.Horizontal)
    lay.VerticalAlignment = Enum.VerticalAlignment.Center
    self._watermark = wm

    local order = 0
    local function nextO() order = order + 1 return order end
    local function sep()
        local f = Instance.new("Frame")
        f.Size = UDim2.new(0, 1, 0, 16)
        f.BackgroundColor3 = PALETTE.stroke
        f.BorderSizePixel = 0
        f.ZIndex = 150
        f.LayoutOrder = nextO()
        f.Parent = wm
    end
    local function textSeg(initial)
        local t = Instance.new("TextLabel")
        t.AutomaticSize = Enum.AutomaticSize.X
        t.Size = UDim2.new(0, 0, 1, 0)
        t.BackgroundTransparency = 1
        t.FontFace = FONT
        t.TextSize = 14
        t.TextColor3 = PALETTE.text
        t.TextYAlignment = Enum.TextYAlignment.Center
        t.Text = initial
        t.ZIndex = 150
        t.LayoutOrder = nextO()
        t.Parent = wm
        return t
    end

    if show.logo ~= false then
        local ic = makeIcon(wm, opts.icon or "logo", UDim2.new(0, 24, 0, 24), Color3.fromRGB(255, 255, 255))
        ic.ZIndex = 150
        ic.LayoutOrder = nextO()
    end
    if show.brand ~= false then
        local brand = textSeg("NewReality")
        brand.TextSize = 15
        local rb = animateBrand(brand)
        table.insert(self._refresh, rb)
    end

    local fpsLabel, timeLabel
    if show.fps ~= false then
        sep()
        fpsLabel = textSeg("FPS 60")
    end
    if show.time ~= false then
        sep()
        timeLabel = textSeg("00:00:00")
    end

    makeDraggable(wm, wm)

    -- Update FPS (smoothed) and time.
    local fps, acc, frames = 60, 0, 0
    local conn
    conn = RunService.RenderStepped:Connect(function(dt)
        frames = frames + 1
        acc = acc + dt
        if acc >= 0.5 then
            fps = math.floor(frames / acc + 0.5)
            frames = 0
            acc = 0
            if fpsLabel then fpsLabel.Text = "FPS " .. fps end
            if timeLabel then timeLabel.Text = os.date("%H:%M:%S") end
        end
    end)
    wm.Destroying:Connect(function() if conn then conn:Disconnect() end end)
    return wm
end

-- Draggable keybind panel listing every keybind, its key and active state.
-- opts: { position=UDim2, width=number, title=string, showInactive=bool }
function Window:keybindList(opts)
    opts = opts or {}
    if self._keybindPanel then self._keybindPanel:Destroy() end
    local width = opts.width or 190
    local showInactive = opts.showInactive ~= false

    local panel = Instance.new("Frame")
    panel.Name = "Keybinds"
    panel.Size = UDim2.new(0, width, 0, 0)
    panel.AutomaticSize = Enum.AutomaticSize.Y
    panel.Position = opts.position or UDim2.new(0, 16, 0, 70)
    panel.BackgroundColor3 = PALETTE.card
    panel.BorderSizePixel = 0
    panel.ZIndex = 150
    panel.Parent = self.screen
    corner(panel, 8)
    stroke(panel, PALETTE.stroke, 1, 0.3)
    self._keybindPanel = panel

    local body = Instance.new("Frame")
    body.BackgroundTransparency = 1
    body.Size = UDim2.new(1, 0, 0, 0)
    body.AutomaticSize = Enum.AutomaticSize.Y
    body.ZIndex = 150
    body.Parent = panel
    listLayout(body, 4)
    padding(body, 10)

    local titleRow = Instance.new("Frame")
    titleRow.Size = UDim2.new(1, 0, 0, 20)
    titleRow.BackgroundTransparency = 1
    titleRow.ZIndex = 150
    titleRow.LayoutOrder = 0
    titleRow.Parent = body
    local titleIcon = makeIcon(titleRow, "keyboard", UDim2.new(0, 16, 0, 16), PALETTE.text)
    titleIcon.AnchorPoint = Vector2.new(0, 0.5)
    titleIcon.Position = UDim2.new(0, 0, 0.5, 0)
    titleIcon.ZIndex = 150
    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, 22, 0, 0)
    title.Size = UDim2.new(1, -22, 1, 0)
    title.FontFace = FONT
    title.TextSize = 15
    title.TextColor3 = PALETTE.text
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.Text = opts.title or "Keybinds"
    title.ZIndex = 150
    title.Parent = titleRow

    local divider = Instance.new("Frame")
    divider.Size = UDim2.new(1, 0, 0, 1)
    divider.BackgroundColor3 = PALETTE.stroke
    divider.BackgroundTransparency = 0.4
    divider.BorderSizePixel = 0
    divider.ZIndex = 150
    divider.LayoutOrder = 1
    divider.Parent = body

    local rows = {}
    for idx, bind in ipairs(self._binds) do
        local row = Instance.new("Frame")
        row.Size = UDim2.new(1, 0, 0, 20)
        row.BackgroundTransparency = 1
        row.ZIndex = 150
        row.LayoutOrder = idx + 1
        row.Parent = body
        local dot = Instance.new("Frame")
        dot.AnchorPoint = Vector2.new(0, 0.5)
        dot.Position = UDim2.new(0, 1, 0.5, 0)
        dot.Size = UDim2.new(0, 7, 0, 7)
        dot.BackgroundColor3 = PALETTE.subtext
        dot.BorderSizePixel = 0
        dot.ZIndex = 150
        dot.Parent = row
        corner(dot, 4)
        local lbl = Instance.new("TextLabel")
        lbl.BackgroundTransparency = 1
        lbl.Position = UDim2.new(0, 16, 0, 0)
        lbl.Size = UDim2.new(1, -76, 1, 0)
        lbl.FontFace = FONT
        lbl.TextSize = 13
        lbl.TextColor3 = PALETTE.text
        lbl.TextXAlignment = Enum.TextXAlignment.Left
        lbl.TextTruncate = Enum.TextTruncate.AtEnd
        lbl.Text = bind.label
        lbl.ZIndex = 150
        lbl.Parent = row
        local keyLbl = Instance.new("TextLabel")
        keyLbl.AnchorPoint = Vector2.new(1, 0.5)
        keyLbl.Position = UDim2.new(1, 0, 0.5, 0)
        keyLbl.Size = UDim2.new(0, 58, 1, 0)
        keyLbl.BackgroundTransparency = 1
        keyLbl.FontFace = FONT
        keyLbl.TextSize = 13
        keyLbl.TextColor3 = PALETTE.subtext
        keyLbl.TextXAlignment = Enum.TextXAlignment.Right
        keyLbl.TextTruncate = Enum.TextTruncate.AtEnd
        keyLbl.Text = ""
        keyLbl.ZIndex = 150
        keyLbl.Parent = row
        rows[idx] = { row = row, dot = dot, lbl = lbl, key = keyLbl, bind = bind }
    end

    makeDraggable(panel, panel)

    local conn
    conn = RunService.RenderStepped:Connect(function()
        if not panel.Visible then return end
        for _, r in ipairs(rows) do
            local keys = r.bind.keys and r.bind.keys() or {}
            r.key.Text = (#keys > 0) and table.concat(keys, "+") or "None"
            local active = r.bind.active and r.bind.active() or false
            r.dot.BackgroundColor3 = active and PALETTE.accent or PALETTE.subtext
            r.lbl.TextColor3 = active and PALETTE.text or PALETTE.subtext
            r.row.Visible = showInactive or active
        end
    end)
    panel.Destroying:Connect(function() if conn then conn:Disconnect() end end)
    return panel
end

function Interface.new(opts)
    opts = opts or {}
    local self = setmetatable({ tabs = {}, groups = {}, _refresh = {}, flags = {}, _binds = {} }, Window)

    local screen = Instance.new("ScreenGui")
    screen.Name = "NewReality"
    screen.ResetOnSpawn = false
    screen.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    screen.IgnoreGuiInset = true
    screen.Parent = guiParent()
    self.screen = screen

    local window = Instance.new("Frame")
    window.Size = UDim2.new(0, 900, 0, 580)
    window.Position = UDim2.new(0.5, -450, 0.5, -290)
    themed(window, "BackgroundColor3", "background")
    window.BorderSizePixel = 0
    window.Parent = screen
    corner(window, 14)
    shadow(window)
    self.window = window

    -- Sidebar
    local sidebar = Instance.new("Frame")
    sidebar.Size = UDim2.new(0, 230, 1, 0)
    themed(sidebar, "BackgroundColor3", "sidebar")
    sidebar.BorderSizePixel = 0
    sidebar.Parent = window
    corner(sidebar, 14)
    local sidebarMask = Instance.new("Frame")
    sidebarMask.Size = UDim2.new(0, 12, 1, 0)
    sidebarMask.Position = UDim2.new(1, -12, 0, 0)
    themed(sidebarMask, "BackgroundColor3", "sidebar")
    sidebarMask.BorderSizePixel = 0
    sidebarMask.Parent = sidebar

    local brandRow = Instance.new("Frame")
    brandRow.Size = UDim2.new(1, -28, 0, 48)
    brandRow.Position = UDim2.new(0, 16, 0, 16)
    brandRow.BackgroundTransparency = 1
    brandRow.Parent = sidebar
    local hasLogo = iconAsset(opts.icon or "logo") ~= nil
    local logoName = opts.icon or "logo"
    if hasLogo then
        local logo = Instance.new("ImageLabel")
        logo.BackgroundTransparency = 1
        logo.Size = UDim2.new(0, 40, 0, 40)
        logo.Image = iconAsset(logoName) or ""
        logo.ImageColor3 = Color3.fromRGB(255, 255, 255)
        logo.ScaleType = Enum.ScaleType.Fit
        logo.AnchorPoint = Vector2.new(0, 0.5)
        logo.Position = UDim2.new(0, 0, 0.5, 0)
        logo.Parent = brandRow
    end
    local brand = Instance.new("TextLabel")
    brand.BackgroundTransparency = 1
    brand.Position = UDim2.new(0, hasLogo and 50 or 0, 0, 0)
    brand.Size = UDim2.new(1, hasLogo and -50 or 0, 1, 0)
    brand.FontFace = FONT
    brand.TextSize = 23
    brand.TextColor3 = PALETTE.text
    brand.TextXAlignment = Enum.TextXAlignment.Left
    brand.Text = "NewReality"
    brand.Parent = brandRow
    local rebuildBrand = animateBrand(brand)
    table.insert(self._refresh, rebuildBrand)

    local sidebarList = Instance.new("ScrollingFrame")
    sidebarList.Position = UDim2.new(0, 10, 0, 70)
    sidebarList.Size = UDim2.new(1, -22, 1, -80)
    sidebarList.BackgroundTransparency = 1
    sidebarList.BorderSizePixel = 0
    sidebarList.ScrollBarThickness = 0
    sidebarList.CanvasSize = UDim2.new(0, 0, 0, 0)
    sidebarList.AutomaticCanvasSize = Enum.AutomaticSize.Y
    sidebarList.Parent = sidebar
    listLayout(sidebarList, 4)
    self.sidebarList = sidebarList

    -- Content
    local content = Instance.new("Frame")
    content.Position = UDim2.new(0, 230, 0, 0)
    content.Size = UDim2.new(1, -230, 1, 0)
    content.BackgroundTransparency = 1
    content.Parent = window

    -- Drag handle sits behind the header so the title bar is draggable, but the
    -- gear and close buttons (created after it) stay on top and remain clickable.
    local topDrag = Instance.new("Frame")
    topDrag.Size = UDim2.new(1, 0, 0, 56)
    topDrag.BackgroundTransparency = 1
    topDrag.Parent = content

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Position = UDim2.new(0, 24, 0, 14)
    title.Size = UDim2.new(1, -48, 0, 24)
    title.FontFace = FONT
    title.TextSize = 22
    title.TextColor3 = PALETTE.text
    title.TextXAlignment = Enum.TextXAlignment.Left
    title.Text = ""
    title.Parent = content
    self.title = title

    local subtitle = Instance.new("TextLabel")
    subtitle.BackgroundTransparency = 1
    subtitle.Position = UDim2.new(0, 24, 0, 37)
    subtitle.Size = UDim2.new(1, -48, 0, 16)
    subtitle.FontFace = FONT
    subtitle.TextSize = 13
    subtitle.TextColor3 = PALETTE.subtext
    subtitle.TextXAlignment = Enum.TextXAlignment.Left
    subtitle.Text = ""
    subtitle.Parent = content
    self.subtitle = subtitle

    local pages = Instance.new("Frame")
    pages.Position = UDim2.new(0, 24, 0, 56)
    pages.Size = UDim2.new(1, -48, 1, -72)
    pages.BackgroundTransparency = 1
    pages.Parent = content
    self.pages = pages

    -- Overlay for popovers, dropdown lists and colour pickers.
    local overlay = Instance.new("Frame")
    overlay.Size = UDim2.new(1, 0, 1, 0)
    overlay.BackgroundTransparency = 1
    overlay.ZIndex = 40
    overlay.Parent = window
    self.overlay = overlay

    -- Close every transient panel currently floating in the overlay. Called when
    -- a new panel opens or when tabs/sub-tabs change so nothing is left hanging.
    self.closeOverlays = function()
        for _, child in ipairs(overlay:GetChildren()) do
            child:Destroy()
        end
    end

    -- Invisible full-window backdrop placed under a panel so a click anywhere
    -- outside it closes the panel. Returns nothing; the panel is added on top.
    self.showBackdrop = function()
        local back = Instance.new("TextButton")
        back.Name = "Backdrop"
        back.Size = UDim2.new(1, 0, 1, 0)
        back.BackgroundTransparency = 1
        back.AutoButtonColor = false
        back.Text = ""
        back.ZIndex = 41
        back.Parent = overlay
        back.MouseButton1Click:Connect(function()
            self.closeOverlays()
        end)
        return back
    end

    -- Keep a floating panel inside the window bounds given its offset and size.
    self.fitPanel = function(xOff, yOff, w, h)
        local size = self.window.AbsoluteSize
        local maxX = math.max(8, size.X - w - 8)
        local maxY = math.max(8, size.Y - h - 8)
        return UDim2.new(0, math.clamp(xOff, 8, maxX), 0, math.clamp(yOff, 8, maxY))
    end

    makeDraggable(window, topDrag)

    -- Hotkey to show/hide the window (RightShift by default).
    self.toggleKey = opts.toggleKey or Enum.KeyCode.RightShift
    UserInputService.InputBegan:Connect(function(input, gpe)
        if gpe then return end
        if input.KeyCode == self.toggleKey then
            self:toggle()
        end
    end)

    local scale = Instance.new("UIScale")
    scale.Scale = 0.92
    scale.Parent = window
    window.BackgroundTransparency = 1
    tween(window, 0.25, { BackgroundTransparency = 0 })
    tween(scale, 0.32, { Scale = 1 }, Enum.EasingStyle.Back)

    return self
end

Interface.Window = Window
Interface.Card = Card

-- Showcase: run the file directly to preview the design. A product script that
-- embeds this kit sets _G.NewRealityShowcase = false before use to skip it.
function Interface.showcase()
    local win = Interface.new({ icon = "logo" })

    -- A neutral component demo. This is only a preview of the kit, it is not a
    -- product layout, so it just shows each control type once.
    local home = win:tab({ name = "Dashboard", icon = "layout-dashboard", group = "Main", subtitle = "Overview of every control" })
    do
        local s = home:sub("Controls")
        local basics = s:card({ title = "Basics", icon = "adjustments", subtitle = "Buttons and toggles", column = "left" })
        basics:button("Run Action", function() end)
        do
            local g, set = win:flag("simpleToggle", true)
            basics:toggle("Simple Toggle", g, set)
        end
        basics:toggle("Toggle With Settings", function() return false end, function() end, function(set)
            set:slider("Inner Value", 0, 100, function() return 40 end, function() end, 0)
            set:toggle("Inner Toggle", function() return true end, function() end)
        end)
        do
            -- Multi keybind that can also be cleared (right click) and fires a callback.
            local g, set = win:flag("bindKeys", { "F" })
            basics:keybind("Bind Keys", g, set, { multi = true, callback = function() end })
        end

        local values = s:card({ title = "Values", icon = "gauge", subtitle = "Sliders and steppers", column = "right" })
        do local g, set = win:flag("speed", 50) values:slider("Speed", 16, 200, g, set, 0) end
        do local g, set = win:flag("multiplier", 1.5) values:slider("Multiplier", 0, 5, g, set, 1) end
        do local g, set = win:flag("count", 3) values:stepper("Count", 0, 10, 1, g, set) end
        do local g, set = win:flag("mode", "Hold") values:segmented("Mode", { "Off", "Hold", "On" }, g, set) end

        local more = home:sub("More")
        more:card({ title = "Labels", icon = "info-circle", column = "left" }):label("This sub-tab proves the top tabs switch correctly.")
    end

    local lists = win:tab({ name = "Selectors", icon = "list", group = "Main", subtitle = "Dropdowns, lists, colours" })
    do
        local s = lists:sub("Selectors")
        local pick = s:card({ title = "Pickers", icon = "filter", column = "left" })
        local single = "Alpha"
        pick:dropdown("Single", { "Alpha", "Beta", "Gamma" }, function() return single end, function(v) single = v end, { search = true })
        local multi = { "Pink" }
        pick:dropdown("Multi", { "Red", "Green", "Blue", "Pink" }, function() return multi end, function(v) multi = v end, { multi = true, search = true })
        local accent = { 251, 149, 255 }
        pick:colorpicker("Accent", function() return accent end, function(v) accent = v end)

        local conf = s:card({ title = "Config List", icon = "device-floppy", column = "right" })
        local cfgSel = "Default"
        conf:list({ "Default", "Rage", "Legit", "Custom" }, function() return cfgSel end, function(v) cfgSel = v end, { search = true })
    end

    local settings = win:tab({ name = "Settings", icon = "settings", group = "Other", subtitle = "Interface options" })
    do
        local s = settings:sub("Settings")
        local ui = s:card({ title = "Interface", icon = "settings", subtitle = "Window behaviour", column = "left" })
        ui:keybind("Toggle UI", function() return win.toggleKey.Name end, function(k)
            local ok, key = pcall(function() return Enum.KeyCode[k] end)
            if ok and key then win.toggleKey = key end
        end)
        ui:toggle("Rainbow Logo", function() return true end, function() end)
        ui:button("Unload", function() win.screen:Destroy() end)

        -- Live theme colours: every tagged part recolours instantly.
        local theme = s:card({ title = "Theme", icon = "palette", subtitle = "Colour every part", column = "left" })
        local function themePicker(label, key)
            theme:colorpicker(label, function() return win:getColor(key) end, function(rgb) win:setColor(key, rgb) end)
        end
        themePicker("Accent", "accent")
        themePicker("Background", "background")
        themePicker("Sidebar", "sidebar")
        themePicker("Cards", "card")
        themePicker("Controls", "control")
        themePicker("Track", "track")
        theme:button("Reset Theme", function() win:resetTheme() end)

        local cfg = s:card({ title = "Save Manager", icon = "device-floppy", subtitle = "Configurations", column = "right" })
        local cfgSel = "default"
        local function cfgList()
            local list = { "default" }
            for _, n in ipairs(win:listConfigs()) do
                if n ~= "default" then table.insert(list, n) end
            end
            return list
        end
        cfg:dropdown("Config", cfgList, function() return cfgSel end, function(v) cfgSel = v end, { search = true })
        local newName = ""
        cfg:input("Name", "new config name", function() return newName end, function(v) newName = v end)
        cfg:button("Create", function()
            if newName ~= "" and win:saveConfig(newName) then
                cfgSel = newName
                newName = ""
                win:refreshAll()
            end
        end)
        cfg:button("Save", function() win:saveConfig(cfgSel) end)
        cfg:button("Load", function() win:loadConfig(cfgSel) end)
        cfg:button("Delete", function()
            if cfgSel ~= "default" and win:deleteConfig(cfgSel) then
                cfgSel = "default"
                win:refreshAll()
            end
        end)
        cfg:toggle("Auto Load Config", function() return false end, function() end)
    end
    return win
end

if _G.NewRealityShowcase ~= false then
    pcall(Interface.showcase)
end

return Interface

